def _snowflake_to_nested(snowflake: Snowflake) -> SnowflakeNested:
    """Convert flat Snowflake to nested format."""
    attrs = SnowflakeAttributes()
    _populate_snowflake_attrs(attrs, snowflake)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        snowflake, _SNOWFLAKE_REL_FIELDS, SnowflakeRelationshipAttributes
    )
    return SnowflakeNested(
        guid=snowflake.guid,
        type_name=snowflake.type_name,
        status=snowflake.status,
        version=snowflake.version,
        create_time=snowflake.create_time,
        update_time=snowflake.update_time,
        created_by=snowflake.created_by,
        updated_by=snowflake.updated_by,
        classifications=snowflake.classifications,
        classification_names=snowflake.classification_names,
        meanings=snowflake.meanings,
        labels=snowflake.labels,
        business_attributes=snowflake.business_attributes,
        custom_attributes=snowflake.custom_attributes,
        pending_tasks=snowflake.pending_tasks,
        proxy=snowflake.proxy,
        is_incomplete=snowflake.is_incomplete,
        provenance_type=snowflake.provenance_type,
        home_id=snowflake.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _snowflake_from_nested(nested: SnowflakeNested) -> Snowflake:
    """Convert nested format to flat Snowflake."""
    attrs = (
        nested.attributes if nested.attributes is not UNSET else SnowflakeAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _SNOWFLAKE_REL_FIELDS,
        SnowflakeRelationshipAttributes,
    )
    return Snowflake(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_snowflake_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _snowflake_to_nested_bytes(snowflake: Snowflake, serde: Serde) -> bytes:
    """Convert flat Snowflake to nested JSON bytes."""
    return serde.encode(_snowflake_to_nested(snowflake))


def _snowflake_from_nested_bytes(data: bytes, serde: Serde) -> Snowflake:
    """Convert nested JSON bytes to flat Snowflake."""
    nested = serde.decode(data, SnowflakeNested)
    return _snowflake_from_nested(nested)


